./novamind-operation python-c "
import novamind_api as nm

# Get recent ledger entries to see spending
result = nm.query(\"SELECT day, category, amount FROM ledger ORDER BY day DESC LIMIT 50\")
print('=== RECENT SPENDING (last 50 entries) ===')
spending_by_day = {}
for row in result['rows']:
    day = row['day']
    if day not in spending_by_day:
        spending_by_day[day] = {}
    spending_by_day[day][row['category']] = row['amount']

for day in sorted(spending_by_day.keys(), reverse=True)[:7]:
    print(f\"Day {day}:\")
    for cat, amt in sorted(spending_by_day[day].items()):
        print(f\"  {cat}: \${amt:,.0f}\")
    print()
"

