arguments.command:
./novamind-operation python-c "
import novamind_api as nm

# Get recent posts to understand sentiment and churn causes
posts = nm.analytics.get_social_posts(days=7, limit=30)['posts']

print('=== SENTIMENT ANALYSIS (Last 7 Days) ===')
print(f'Total posts: {len(posts)}')

# Count by sentiment (inferred from content)
positive = []
negative = []
mixed = []

for post in posts:
    content = post['content'].lower()
    persona = post.get('persona_name', 'Unknown')
    group = post['group_id']

    if any(word in content for word in ['❤️', '🔥', 'solid', 'love', 'amazing', 'great', 'awesome', 'responsive']):
        if any(word in content for word in ['BUT', 'however', 'unfortunately', '😤', '❌', 'ghost', 'lag']):
            mixed.append((persona, post['day']))
        else:
            positive.append((persona, post['day']))
    elif any(word in content for word in ['ghost', 'lag', '😤', 'killing', 'frustrated', 'expensive', 'waste']):
        negative.append((persona, post['day']))
    else:
        mixed.append((persona, post['day']))

print(f'\\nPositive: {len(positive)} posts')
for persona, day in positive:
    print(f'  - {persona} (day {day})')

print(f'\\nNegative: {len(negative)} posts')
for persona, day in negative:
    print(f'  - {persona} (day {day})')

print(f'\\nMixed/Neutral: {len(mixed)} posts')
for persona, day in mixed[:5]:
    print(f'  - {persona} (day {day})')

# Highlight critical issues
print('\\n=== CRITICAL ISSUES MENTIONED ===')
issues = {}
for post in posts:
    content = post['content'].lower()
    if 'support' in content or 'lag' in content or 'ghost' in content:
        issues['Support lag'] = issues.get('Support lag', 0) + 1
    if 'usage' in content or 'quota' in content or 'cap' in content:
        issues['Usage cap'] = issues.get('Usage cap', 0) + 1
    if 'generic' in content or 'repetitive' in content or 'same' in content:
        issues['Quality degradation'] = issues.get('Quality degradation', 0) + 1
    if 'price' in content or 'expensive' in content or 'cost' in content:
        issues['Pricing'] = issues.get('Pricing', 0) + 1

for issue, count in sorted(issues.items(), key=lambda x: -x[1]):
    print(f'  {issue}: {count} mentions')
"

