./novamind-operation python-c "
import novamind_api as nm

# Get critical financial data
print('=== FINANCIAL LEDGER (Last 50 entries) ===')
result = nm.query('SELECT day, amount, category FROM ledger ORDER BY day DESC LIMIT 50')
total_by_category = {}
for row in result['rows']:
    cat = row['category']
    if cat not in total_by_category:
        total_by_category[cat] = 0
    total_by_category[cat] += row['amount']

print('Totals by category (last 50 entries):')
for cat, total in sorted(total_by_category.items()):
    print(f'  {cat:30s}: {total:12,.0f}')

print('\n=== SUBSCRIBER BREAKDOWN ===')
result = nm.query('SELECT group_id, COUNT(*) as n, status FROM subscriptions WHERE status IN (\"active\", \"cancelled\") GROUP BY group_id, status ORDER BY group_id')
active = {}
for row in result['rows']:
    if row['status'] == 'active':
        active[row['group_id']] = row['n']

print('Active subscribers by group:')
for group in sorted(active.keys()):
    print(f'  {group:5s}: {active[group]:4d}')
print(f'  TOTAL: {sum(active.values()):4d}')
"

